command:
mkdir -p space && printf 'metrics:
  - {id: m1, dimension: performance}
' > space/metrics.yaml && printf 'dimensions: {performance: {enabled: true}}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --config space/config.yaml > out.txt 2>err.txt && head -20 out.txt | grep -q 'solo-scale' && head -20 out.txt | grep -q 'self-observation' && echo ok 1>&2
